// Define an interface for MainActivity to handle permission requests from WebAppInterface
interface PermissionRequester {
    fun requestCameraPermission(requestId: Int)
    fun onCameraPermissionResult(granted: Boolean)
    fun showFileChooser(filePathCallback: ValueCallback<Array<Uri>>?, fileChooserParams: WebChromeClient.FileChooserParams?)
}

// WebAppInterface: The bridge between JavaScript and Kotlin
class WebAppInterface(
    private val context: Context,
    private val webView: WebView,
    private val permissionRequester: PermissionRequester
) {
    private val TAG = "WebAppInterface"
    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences("WebAppLocalStorage", Context.MODE_PRIVATE)

    @JavascriptInterface
    fun showToast(toastMessage: String) {
        Log.d(TAG, "JS called showToast: $toastMessage")
        Toast.makeText(context, toastMessage, Toast.LENGTH_SHORT).show()
    }

    // Camera Access
    @JavascriptInterface
    fun requestCameraAccess() {
        Log.d(TAG, "JS called requestCameraAccess")
        // Delegate permission request to the Activity
        permissionRequester.requestCameraPermission(MainActivity.CAMERA_PERMISSION_REQUEST_CODE)
    }

    // Local Storage
    @JavascriptInterface
    fun saveData(key: String, value: String) {
        Log.d(TAG, "JS called saveData: key=$key, value=$value")
        sharedPreferences.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun loadData(key: String) {
        Log.d(TAG, "JS called loadData: key=$key")
        val value = sharedPreferences.getString(key, null)
        Log.d(TAG, "Loaded data for key=$key: $value")
        // Send data back to JavaScript
        val jsonValue = if (value != null) JSONObject.quote(value) else "null"
        webView.post {
            webView.evaluateJavascript("window.onNativeDataLoaded('$key', $jsonValue);", null)
        }
    }

    @JavascriptInterface
    fun removeData(key: String) {
        Log.d(TAG, "JS called removeData: key=$key")
        sharedPreferences.edit().remove(key).apply()
    }

    // Push Notifications
    @JavascriptInterface
    fun getPushNotificationToken() {
        Log.d(TAG, "JS called getPushNotificationToken")
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (!task.isSuccessful) {
                Log.w(TAG, "Fetching FCM registration token failed", task.exception)
                webView.post {
                    webView.evaluateJavascript("window.onPushNotificationTokenReceived(null);", null)
                }
                return@addOnCompleteListener
            }

            val token = task.result
            Log.d(TAG, "FCM Token: $token")
            // Send token back to JavaScript
            val jsonToken = if (token != null) JSONObject.quote(token) else "null"
            webView.post {
                webView.evaluateJavascript("window.onPushNotificationTokenReceived($jsonToken);", null)
            }
        }
    }
}

class MainActivity : AppCompatActivity(), PermissionRequester {

    private lateinit var webView: WebView
    private var mUploadMessage: ValueCallback<Array<Uri>>? = null

    companion object {
        const val CAMERA_PERMISSION_REQUEST_CODE = 101
        const val FILE_CHOOSER_REQUEST_CODE = 102
        // Replace with your actual web app URL
        const val WEB_APP_URL = "file:///android_asset/web/index.html"
        // For testing, you could use a remote URL: "https://your.mobile.web.app/index.html"
    }

    // Activity Result Launcher for camera permission
    private val requestCameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted: Boolean ->
        onCameraPermissionResult(isGranted)
    }

    // Activity Result Launcher for file chooser
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        var results: Array<Uri>? = null
        if (result.resultCode == RESULT_OK) {
            result.data?.let { intent ->
                if (intent.dataString != null) {
                    results = arrayOf(Uri.parse(intent.dataString))
                } else if (intent.clipData != null) {
                    val count = intent.clipData!!.itemCount
                    results = Array(count) { i -> intent.clipData!!.getItemAt(i).uri }
                }
            }
        }
        mUploadMessage?.onReceiveValue(results)
        mUploadMessage = null
    }

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView = findViewById(R.id.webView)

        setupWebView()
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true // Enable JavaScript
            domStorageEnabled = true // Enable Web Storage (localStorage, sessionStorage)
            allowFileAccess = true
            allowContentAccess = true
            mediaPlaybackRequiresUserGesture = false // Allow autoplay for media
        }

        // Set WebViewClient to handle page navigation within the WebView
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url?.toString()
                Log.d("WebViewClient", "Loading URL: $url")
                // Load URL within the WebView itself
                view?.loadUrl(url ?: return false)
                return true
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                Log.d("WebViewClient", "Page finished loading: $url")
                // Inject an example JS function for the web app to call
                // This is optional, but useful for initial setup or testing
                webView.evaluateJavascript("""
                    window.showAlertFromNative = function(message) {
                        alert("Alert from Native: " + message);
                    };
                    window.nativeReady = true; // Signal to JS that native bridge is ready
                    console.log('Native bridge initialized');
                """, null)
            }
        }

        // Set WebChromeClient to handle JavaScript dialogs, favicons, titles, and progress
        webView.webChromeClient = object : WebChromeClient() {
            override fun onJsAlert(view: WebView?, url: String?, message: String?, result: android.webkit.JsResult?): Boolean {
                AlertDialog.Builder(view?.context)
                    .setTitle("Web App Alert")
                    .setMessage(message)
                    .setPositiveButton(android.R.string.ok) { dialog, _ ->
                        dialog.dismiss()
                        result?.confirm()
                    }
                    .setCancelable(false)
                    .create()
                    .show()
                return true
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                mUploadMessage = filePathCallback
                showFileChooser(filePathCallback, fileChooserParams)
                return true
            }
        }

        // Add the JavaScript interface
        webView.addJavascriptInterface(WebAppInterface(this, webView, this), "Android")

        // Load the web app URL
        webView.loadUrl(WEB_APP_URL)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    // region PermissionRequester Implementation

    override fun requestCameraPermission(requestId: Int) {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            onCameraPermissionResult(true)
        } else {
            requestCameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    override fun onCameraPermissionResult(granted: Boolean) {
        val jsCallback = "window.onCameraPermissionResult(${granted});"
        Log.d("MainActivity", "Sending camera permission result to JS: $jsCallback")
        webView.post {
            webView.evaluateJavascript(jsCallback, null)
        }
    }

    override fun showFileChooser(
        filePathCallback: ValueCallback<Array<Uri>>?,
        fileChooserParams: WebChromeClient.FileChooserParams?
    ) {
        if (filePathCallback == null) {
            Log.w("MainActivity", "filePathCallback is null")
            return
        }

        mUploadMessage = filePathCallback
        val intent = fileChooserParams?.createIntent()
        try {
            fileChooserLauncher.launch(intent)
        } catch (e: Exception) {
            Log.e("MainActivity", "Error launching file chooser: ${e.message}", e)
            mUploadMessage?.onReceiveValue(null)
            mUploadMessage = null
            Toast.makeText(this, "Cannot open file picker", Toast.LENGTH_SHORT).show()
        }
    }

    // endregion
}

